const data = $input.first().json.body;
const staticData = $getWorkflowStaticData('global');

if (!staticData.entradas) staticData.entradas = [];

const ahora = new Date();
const fechaStr = ahora.toLocaleString('es-ES', { timeZone: 'Europe/Madrid' });
const fechaCorta = ahora.toLocaleDateString('es-ES', { timeZone: 'Europe/Madrid' });

// Modo resumen: estadisticas generales
if (data.accion === 'resumen') {
  const entradas = staticData.entradas;
  const tipos = ['evento', 'incidencia', 'logro', 'recordatorio', 'acta'];
  const por_tipo = {};
  tipos.forEach(t => por_tipo[t] = entradas.filter(e => e.tipo === t).length);

  // Entradas de los ultimos 7 dias
  const hace7dias = ahora.getTime() - (7 * 24 * 60 * 60 * 1000);
  const recientes = entradas.filter(e => e.timestamp > hace7dias);

  return [{ json: {
    status: 'ok',
    resumen: {
      total_entradas: entradas.length,
      por_tipo,
      ultimos_7_dias: recientes.length,
      primera_entrada: entradas.length > 0 ? entradas[0].fecha : null,
      ultima_entrada: entradas.length > 0 ? entradas[entradas.length - 1].fecha : null
    }
  } }];
}

// Modo consulta: buscar entradas
if (data.accion === 'consultar') {
  let resultados = staticData.entradas;
  if (data.tipo) resultados = resultados.filter(e => e.tipo === data.tipo);
  if (data.responsable) resultados = resultados.filter(e =>
    e.responsable && e.responsable.toLowerCase().includes(data.responsable.toLowerCase())
  );
  if (data.fecha) resultados = resultados.filter(e => e.fecha_corta === data.fecha);
  if (data.buscar) {
    const termino = data.buscar.toLowerCase();
    resultados = resultados.filter(e =>
      e.titulo.toLowerCase().includes(termino) ||
      e.descripcion.toLowerCase().includes(termino)
    );
  }
  // Devolver los ultimos 50 resultados (mas recientes primero)
  const ultimos = resultados.slice(-50).reverse();
  return [{ json: { status: 'ok', total: resultados.length, mostrando: ultimos.length, entradas: ultimos } }];
}

// Modo borrar (protegido)
if (data.accion === 'borrar_todo' && data.confirmar === true) {
  const total = staticData.entradas.length;
  staticData.entradas = [];
  return [{ json: { status: 'ok', mensaje: `Se han borrado ${total} entradas del diario` } }];
}

// Registrar nueva entrada
const tipos_validos = ['evento', 'incidencia', 'logro', 'recordatorio', 'acta'];
if (!data.tipo || !data.titulo || !data.descripcion) {
  return [{ json: {
    status: 'error',
    mensaje: 'Campos obligatorios: tipo (evento/incidencia/logro/recordatorio/acta), titulo, descripcion'
  } }];
}
if (!tipos_validos.includes(data.tipo)) {
  return [{ json: { status: 'error', mensaje: 'Tipo debe ser: evento, incidencia, logro, recordatorio o acta' } }];
}

const entrada = {
  id: staticData.entradas.length + 1,
  tipo: data.tipo,
  titulo: data.titulo,
  descripcion: data.descripcion,
  responsable: data.responsable || 'No especificado',
  fecha: fechaStr,
  fecha_corta: fechaCorta,
  timestamp: ahora.getTime()
};

staticData.entradas.push(entrada);
return [{ json: { status: 'ok', mensaje: 'Entrada registrada en el diario', entrada } }];
